# Chicc Style Image Fixer / Smart Renamer
# Place this file and "Run Chicc Image Fixer.bat" inside the website's images folder.
# The script previews changes first and NEVER overwrites an existing file.

$ErrorActionPreference = "Stop"

function Normalize-ImageName([string]$Text) {
    $name = [System.IO.Path]::GetFileName($Text)
    while ($true) {
        $ext = [System.IO.Path]::GetExtension($name).ToLowerInvariant()
        if ($ext -eq ".jpg" -or $ext -eq ".jpeg") {
            $name = [System.IO.Path]::GetFileNameWithoutExtension($name)
        } else {
            break
        }
    }
    return (($name.ToLowerInvariant()) -replace '[^a-z0-9]', '')
}

