$mapping = $mappingJson | ConvertFrom-Json
foreach ($record in $mapping) {
    $record | Add-Member -NotePropertyName targetNorm -NotePropertyValue (Normalize-ImageName $record.target)
    $record | Add-Member -NotePropertyName productNorm -NotePropertyValue (Normalize-ImageName $record.product)
    $record | Add-Member -NotePropertyName aliasNorms -NotePropertyValue @($record.aliases | ForEach-Object { Normalize-ImageName $_ } | Where-Object { $_ } | Select-Object -Unique)
    $record | Add-Member -NotePropertyName colorNorms -NotePropertyValue @($record.colorAliases | ForEach-Object { Normalize-ImageName $_ } | Where-Object { $_ } | Sort-Object Length -Descending | Select-Object -Unique)
    $record | Add-Member -NotePropertyName skuNorms -NotePropertyValue @($record.skus | ForEach-Object { Normalize-ImageName $_ } | Where-Object { $_ } | Select-Object -Unique)
}

$files = Get-ChildItem -LiteralPath $PSScriptRoot -File | Where-Object {
    $_.Name -match '(?i)\.(jpe?g)(\.(jpe?g))*$'
}

if (-not $files) {
    Write-Host "Tidak ada file JPG/JPEG di folder:" -ForegroundColor Yellow
    Write-Host $PSScriptRoot
    Read-Host "Tekan Enter untuk menutup"
    exit 0
}

$plans = @()
$unmatched = @()
$ambiguous = @()

foreach ($file in $files) {
    $base = Normalize-ImageName $file.Name
    $scored = @()

    foreach ($record in $mapping) {
        $score = 0

        if ($base -eq $record.targetNorm) {
            $score = 10000
        } elseif ($record.aliasNorms -contains $base) {
            $score = 9000
        } else {
            if ($record.productNorm -and $base.Contains($record.productNorm)) {
                $score += 250
            }

            $bestColor = 0
            foreach ($colorNorm in $record.colorNorms) {
                if ($colorNorm -and $base.Contains($colorNorm)) {
                    $bestColor = [Math]::Max($bestColor, 120 + $colorNorm.Length)
                }
            }
            $score += $bestColor

            foreach ($skuNorm in $record.skuNorms) {
                if ($skuNorm -and $base.Contains($skuNorm)) {
                    $score += 550
                    break
                }
            }
        }

        if ($score -ge 370) {
            $scored += [PSCustomObject]@{ Record = $record; Score = $score }
        }
    }

    if (-not $scored) {
        $unmatched += $file.Name
        continue
    }

    $maxScore = ($scored | Measure-Object -Property Score -Maximum).Maximum
    $winners = @($scored | Where-Object { $_.Score -eq $maxScore })

    if ($winners.Count -ne 1) {
        $labels = ($winners | ForEach-Object { $_.Record.label }) -join " / "
        $ambiguous += "$($file.Name) => $labels"
        continue
    }

    $record = $winners[0].Record
    $newName = "$($record.target).jpg"
    $plans += [PSCustomObject]@{
        File = $file
        OldName = $file.Name
        NewName = $newName
        Label = $record.label
    }
}

Write-Host ""
Write-Host "PERAPI NAMA FOTO CHICC STYLE" -ForegroundColor Magenta
Write-Host "========================"
Write-Host "Folder             : $PSScriptRoot"
Write-Host "File JPG diperiksa : $($files.Count)"
Write-Host "Siap dirapikan     : $($plans.Count)" -ForegroundColor Green
Write-Host "Perlu dipilih      : $($ambiguous.Count)" -ForegroundColor Yellow
Write-Host "Belum cocok        : $($unmatched.Count)" -ForegroundColor Yellow
Write-Host ""

$plans | Select-Object -First 30 | ForEach-Object {
    Write-Host "$($_.OldName)  ->  $($_.NewName)"
}
if ($plans.Count -gt 30) {
    Write-Host "... dan $($plans.Count - 30) file lainnya."
}

$answer = Read-Host "Ketik YES untuk menjalankan perubahan nama"
if ($answer -cne "YES") {
    Write-Host "Tidak ada file yang diubah." -ForegroundColor Yellow
    Read-Host "Tekan Enter untuk menutup"
    exit 0
}

$renamed = @()
$skipped = @()

foreach ($plan in $plans) {
    $destination = Join-Path $PSScriptRoot $plan.NewName

    if ($plan.OldName -ceq $plan.NewName) {
        $renamed += "Sudah benar: $($plan.OldName)"
        continue
    }

    $sameIgnoringCase = $plan.OldName -ieq $plan.NewName
    if ((Test-Path -LiteralPath $destination) -and -not $sameIgnoringCase) {
        $skipped += "$($plan.OldName) => $($plan.NewName) (nama tujuan sudah ada)"
        continue
    }

    try {
        if ($sameIgnoringCase) {
            $temporary = "__chicc_temp_$([Guid]::NewGuid().ToString('N')).jpg"
            Rename-Item -LiteralPath $plan.File.FullName -NewName $temporary
            Rename-Item -LiteralPath (Join-Path $PSScriptRoot $temporary) -NewName $plan.NewName
        } else {
            Rename-Item -LiteralPath $plan.File.FullName -NewName $plan.NewName
        }
        $renamed += "$($plan.OldName) => $($plan.NewName)"
    } catch {
        $skipped += "$($plan.OldName) => $($plan.NewName) ($($_.Exception.Message))"
    }
}

$logPath = Join-Path $PSScriptRoot "chicc-image-rename-log.txt"
$log = @(
    "CHICC STYLE IMAGE RENAME LOG",
    "Dibuat: $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')",
    "",
    "SUDAH DIGANTI / SUDAH BENAR",
    "-------------------------"
) + $renamed + @(
    "",
    "DILEWATI",
    "-------"
) + $skipped + @(
    "",
    "PERLU DIPILIH — GANTI MANUAL SESUAI CHICC_IMAGE_RENAME_GUIDE.txt",
    "--------------------------------------------------------------"
) + $ambiguous + @(
    "",
    "BELUM COCOK — GANTI MANUAL SESUAI CHICC_IMAGE_RENAME_GUIDE.txt",
    "-------------------------------------------------------------"
) + $unmatched

$log | Set-Content -LiteralPath $logPath -Encoding UTF8

Write-Host ""
Write-Host "Selesai." -ForegroundColor Green
Write-Host "Diubah / sudah benar : $($renamed.Count)"
Write-Host "Dilewati              : $($skipped.Count)"
Write-Host "Perlu dipilih         : $($ambiguous.Count)"
Write-Host "Belum cocok           : $($unmatched.Count)"
Write-Host "Catatan hasil: $logPath"
Read-Host "Tekan Enter untuk menutup"
